from docx.enum.table import WD_TABLE_ALIGNMENT
from docx.enum.text import WD_ALIGN_PARAGRAPH, WD_BREAK
from docx.oxml import OxmlElement
from docx.oxml.ns import qn
from docx.shared import Mm, Pt


OUTPUT_PATH = "Переддипломна_практика_Розробка_вебдодатку_для_генерації_QR_кодів.docx"


def set_cell_text(cell, text, bold=False, align=WD_ALIGN_PARAGRAPH.LEFT):
    cell.text = ""
    paragraph = cell.paragraphs[0]
    paragraph.alignment = align
    run = paragraph.add_run(text)
    run.bold = bold
    run.font.name = "Times New Roman"
    run._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    run.font.size = Pt(14)


def add_field(paragraph, field_code):
    run = paragraph.add_run()
    fld_char_begin = OxmlElement("w:fldChar")
    fld_char_begin.set(qn("w:fldCharType"), "begin")
    run._r.append(fld_char_begin)

    instr_text = OxmlElement("w:instrText")
    instr_text.set(qn("xml:space"), "preserve")
    instr_text.text = field_code
    run._r.append(instr_text)

    fld_char_separate = OxmlElement("w:fldChar")
    fld_char_separate.set(qn("w:fldCharType"), "separate")
    run._r.append(fld_char_separate)

    placeholder = paragraph.add_run(" ")
    placeholder.font.name = "Times New Roman"
    placeholder._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    placeholder.font.size = Pt(14)

    fld_char_end = OxmlElement("w:fldChar")
    fld_char_end.set(qn("w:fldCharType"), "end")
    placeholder._r.append(fld_char_end)


def force_times_new_roman(run, size=14, bold=None, italic=None):
    run.font.name = "Times New Roman"
    run._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    run.font.size = Pt(size)
    if bold is not None:
        run.bold = bold
    if italic is not None:
        run.italic = italic


def add_paragraph(doc, text="", *, style="Normal", align=WD_ALIGN_PARAGRAPH.JUSTIFY, first_line=True, bold=False):
    paragraph = doc.add_paragraph(style=style)
    paragraph.alignment = align
    if style == "Normal" and first_line:
        paragraph.paragraph_format.first_line_indent = Mm(12.5)
    run = paragraph.add_run(text)
    force_times_new_roman(run, bold=bold)
    return paragraph


def add_heading(doc, text, level):
    paragraph = doc.add_paragraph(style=f"Heading {level}")
    paragraph.alignment = WD_ALIGN_PARAGRAPH.CENTER if level == 1 else WD_ALIGN_PARAGRAPH.LEFT
    run = paragraph.add_run(text)
    force_times_new_roman(run, bold=True)
    return paragraph


def add_figure_placeholder(doc, title):
    p1 = add_paragraph(doc, title, align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False)
    p1.paragraph_format.space_before = Pt(6)
    p1.paragraph_format.space_after = Pt(0)
    p2 = add_paragraph(doc, "[МІСЦЕ ДЛЯ РИСУНКА]", align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False)
    p2.paragraph_format.space_after = Pt(6)


def configure_document(doc):
    section = doc.sections[0]
    section.top_margin = Mm(20)
    section.bottom_margin = Mm(20)
    section.left_margin = Mm(30)
    section.right_margin = Mm(10)
    section.different_first_page_header_footer = True

    styles = doc.styles

    normal = styles["Normal"]
    normal.font.name = "Times New Roman"
    normal._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    normal.font.size = Pt(14)
    normal.paragraph_format.line_spacing = 1.5
    normal.paragraph_format.space_before = Pt(0)
    normal.paragraph_format.space_after = Pt(0)
    normal.paragraph_format.first_line_indent = Mm(12.5)

    for style_name, size, before, after, alignment in [
        ("Heading 1", 14, 12, 12, WD_ALIGN_PARAGRAPH.CENTER),
        ("Heading 2", 14, 12, 6, WD_ALIGN_PARAGRAPH.LEFT),
    ]:
        style = styles[style_name]
        style.font.name = "Times New Roman"
        style._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
        style.font.size = Pt(size)
        style.font.bold = True
        style.paragraph_format.line_spacing = 1.5
        style.paragraph_format.space_before = Pt(before)
        style.paragraph_format.space_after = Pt(after)
        style.paragraph_format.first_line_indent = Mm(0)
        style.paragraph_format.alignment = alignment

    settings_element = doc.settings.element
    update_fields = OxmlElement("w:updateFields")
    update_fields.set(qn("w:val"), "true")
    settings_element.append(update_fields)

    footer = section.footer
    footer_p = footer.paragraphs[0]
    footer_p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    add_field(footer_p, " PAGE ")


