def add_toc(doc):
    add_heading(doc, "ЗМІСТ", 1)
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.LEFT
    add_field(p, ' TOC \\\\o "1-2" \\\\h \\\\z \\\\u ')
    doc.add_page_break()


